/* ── MODAL ── */
const modal = document.getElementById('project-modal');
const modalBox = modal.querySelector('.modal-box');

function openModal(key) {
  const p = PROJECTS[key]; if (!p) return;
  document.getElementById('modal-year').textContent = p.year;
  document.getElementById('modal-star').style.display = p.star ? 'inline-flex' : 'none';
  document.getElementById('modal-title').textContent = p.title;
  document.getElementById('modal-sub').textContent = p.sub;
  document.getElementById('modal-badges').innerHTML = p.badges.map(b => `<span class="modal-badge">${b}</span>`).join('');
  const _g = window.IMG_GALLERIES && window.IMG_GALLERIES[key];
  document.getElementById('modal-body').innerHTML = (_g ? _renderGallery(key) : `<div class="modal-mock">${p.mock}</div>`)
    + `<p class="modal-section-title">Description</p>
    <p class="modal-desc">${p.desc}</p>
    <p class="modal-section-title">Fonctionnalités clés</p>
    <div class="modal-features">
      ${p.features.map(f => `<div class="modal-feature"><div class="mfi ${f.cl}"><i class="fas ${f.ic}"></i></div><span>${f.tx}</span></div>`).join('')}
    </div>`;
  window._gIdx = 0;
  modal.classList.add('open');
  document.body.style.overflow = 'hidden';
  modalBox.scrollTop = 0;
}

function closeModal() { modal.classList.remove('open'); document.body.style.overflow = ''; }

document.querySelectorAll('.project-card').forEach(card => {
  card.addEventListener('click', () => openModal(card.dataset.project));
});

