window._gIdx = 0;

function _renderGallery(key) {
  var g = window.IMG_GALLERIES[key];
  if (!g || !g.length) return '';
  var thumbs = '';
  if (g.length > 1) {
    thumbs = '<div class="gallery-thumbs" id="gthumbs">';
    for (var i = 0; i < g.length; i++) {
      thumbs += '<div class="gallery-thumb' + (i === 0 ? ' active' : '') + '" onclick="gSet(' + i + ')">'
        + '<img src="' + g[i].src + '" alt="' + g[i].label + '" loading="lazy"/></div>';
    }
    thumbs += '</div>';
  }
  var arrows = g.length > 1
    ? '<button class="gallery-arrow prev" onclick="gNav(-1)"><i class="fas fa-chevron-left"></i></button>'
    + '<button class="gallery-arrow next" onclick="gNav(1)"><i class="fas fa-chevron-right"></i></button>'
    : '';
  return '<div class="modal-gallery" id="mg" data-key="' + key + '">'
    + '<div class="gallery-main">'
    + '<img id="gmi" src="' + g[0].src + '" alt="' + g[0].label + '"/>'
    + arrows
    + '<span class="gallery-label" id="glbl">' + g[0].label + '</span>'
    + '<span class="gallery-counter" id="gctr">1 / ' + g.length + '</span>'
    + '</div>'
    + thumbs
    + '</div>';
}

function gSet(i) {
  var mg = document.getElementById('mg');
  if (!mg) return;
  var g = window.IMG_GALLERIES[mg.dataset.key];
  if (!g) return;
  window._gIdx = (i + g.length) % g.length;
  var mi = document.getElementById('gmi');
  mi.style.opacity = '0';
  setTimeout(function () {
    mi.src = g[window._gIdx].src;
    mi.style.opacity = '1';
    document.getElementById('glbl').textContent = g[window._gIdx].label;
    document.getElementById('gctr').textContent = (window._gIdx + 1) + ' / ' + g.length;
    document.querySelectorAll('.gallery-thumb').forEach(function (t, j) { t.classList.toggle('active', j === window._gIdx); });
  }, 150);
}

function gNav(d) {
  var mg = document.getElementById('mg');
  if (!mg) return;
  var g = window.IMG_GALLERIES[mg.dataset.key];
  if (g) gSet(window._gIdx + d);
}

